CREATE TYPE "IntegrationPublisherStatus" AS ENUM ('PENDING','VERIFIED','SUSPENDED','REJECTED');
CREATE TYPE "IntegrationListingType" AS ENUM ('CONNECTOR','AUTOMATION_TEMPLATE','WEBHOOK_APP','API_APP');
CREATE TYPE "IntegrationListingVisibility" AS ENUM ('PRIVATE','ORGANIZATION','PUBLIC');
CREATE TYPE "IntegrationListingStatus" AS ENUM ('DRAFT','IN_REVIEW','CHANGES_REQUESTED','PUBLISHED','SUSPENDED','ARCHIVED');
CREATE TYPE "IntegrationReviewStatus" AS ENUM ('PENDING','APPROVED','CHANGES_REQUESTED','REJECTED');
CREATE TYPE "IntegrationInstallationStatus" AS ENUM ('ACTIVE','PAUSED','ERROR','UNINSTALLED');
CREATE TYPE "IntegrationCertificationStatus" AS ENUM ('ACTIVE','EXPIRED','REVOKED');
CREATE TYPE "IntegrationIncidentStatus" AS ENUM ('OPEN','INVESTIGATING','MITIGATED','RESOLVED');
CREATE TABLE "IntegrationPublisher" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"ownerUserId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"websiteUrl" TEXT,"status" "IntegrationPublisherStatus" NOT NULL DEFAULT 'PENDING',"verifiedByUserId" TEXT,"verifiedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "IntegrationPublisher_organizationId_name_key" ON "IntegrationPublisher"("organizationId","name");
CREATE INDEX "IntegrationPublisher_organizationId_status_idx" ON "IntegrationPublisher"("organizationId","status");
CREATE TABLE "IntegrationMarketplaceListing" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"publisherId" TEXT NOT NULL,"createdByUserId" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"description" TEXT,"type" "IntegrationListingType" NOT NULL,"visibility" "IntegrationListingVisibility" NOT NULL DEFAULT 'ORGANIZATION',"status" "IntegrationListingStatus" NOT NULL DEFAULT 'DRAFT',"version" TEXT NOT NULL,"categories" TEXT[] DEFAULT ARRAY[]::TEXT[],"requiredScopes" TEXT[] DEFAULT ARRAY[]::TEXT[],"manifest" JSONB,"submittedAt" TIMESTAMP(3),"publishedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
ALTER TABLE "IntegrationMarketplaceListing" ADD CONSTRAINT "IntegrationMarketplaceListing_publisherId_fkey" FOREIGN KEY ("publisherId") REFERENCES "IntegrationPublisher"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE UNIQUE INDEX "IntegrationMarketplaceListing_organizationId_slug_version_key" ON "IntegrationMarketplaceListing"("organizationId","slug","version");
CREATE INDEX "IntegrationMarketplaceListing_organizationId_status_visibility_idx" ON "IntegrationMarketplaceListing"("organizationId","status","visibility");
CREATE TABLE "IntegrationMarketplaceReview" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"listingId" TEXT NOT NULL,"requestedByUserId" TEXT NOT NULL,"reviewedByUserId" TEXT,"status" "IntegrationReviewStatus" NOT NULL DEFAULT 'PENDING',"submissionNotes" TEXT,"reviewNotes" TEXT,"findings" TEXT[] DEFAULT ARRAY[]::TEXT[],"reviewedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
ALTER TABLE "IntegrationMarketplaceReview" ADD CONSTRAINT "IntegrationMarketplaceReview_listingId_fkey" FOREIGN KEY ("listingId") REFERENCES "IntegrationMarketplaceListing"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE INDEX "IntegrationMarketplaceReview_organizationId_status_createdAt_idx" ON "IntegrationMarketplaceReview"("organizationId","status","createdAt");
CREATE TABLE "IntegrationInstallation" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"listingId" TEXT NOT NULL,"installedByUserId" TEXT NOT NULL,"updatedByUserId" TEXT NOT NULL,"status" "IntegrationInstallationStatus" NOT NULL DEFAULT 'ACTIVE',"installedVersion" TEXT NOT NULL,"configuration" JSONB,"autoUpdate" BOOLEAN NOT NULL DEFAULT true,"lastHealthAt" TIMESTAMP(3),"lastError" TEXT,"uninstalledAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
ALTER TABLE "IntegrationInstallation" ADD CONSTRAINT "IntegrationInstallation_listingId_fkey" FOREIGN KEY ("listingId") REFERENCES "IntegrationMarketplaceListing"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE UNIQUE INDEX "IntegrationInstallation_organizationId_listingId_key" ON "IntegrationInstallation"("organizationId","listingId");
CREATE INDEX "IntegrationInstallation_organizationId_status_updatedAt_idx" ON "IntegrationInstallation"("organizationId","status","updatedAt");
CREATE TABLE "IntegrationMarketplaceRating" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"listingId" TEXT NOT NULL,"userId" TEXT NOT NULL,"rating" INTEGER NOT NULL,"title" TEXT NOT NULL,"body" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
ALTER TABLE "IntegrationMarketplaceRating" ADD CONSTRAINT "IntegrationMarketplaceRating_listingId_fkey" FOREIGN KEY ("listingId") REFERENCES "IntegrationMarketplaceListing"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE UNIQUE INDEX "IntegrationMarketplaceRating_organizationId_listingId_userId_key" ON "IntegrationMarketplaceRating"("organizationId","listingId","userId");
CREATE INDEX "IntegrationMarketplaceRating_listingId_rating_idx" ON "IntegrationMarketplaceRating"("listingId","rating");
CREATE TABLE "IntegrationCertification" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"listingId" TEXT NOT NULL,"certifiedByUserId" TEXT NOT NULL,"type" TEXT NOT NULL,"status" "IntegrationCertificationStatus" NOT NULL DEFAULT 'ACTIVE',"validFrom" TIMESTAMP(3) NOT NULL,"validUntil" TIMESTAMP(3),"evidence" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
ALTER TABLE "IntegrationCertification" ADD CONSTRAINT "IntegrationCertification_listingId_fkey" FOREIGN KEY ("listingId") REFERENCES "IntegrationMarketplaceListing"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE INDEX "IntegrationCertification_organizationId_status_validUntil_idx" ON "IntegrationCertification"("organizationId","status","validUntil");
CREATE TABLE "IntegrationMarketplaceIncident" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"listingId" TEXT NOT NULL,"installationId" TEXT NOT NULL,"reportedByUserId" TEXT NOT NULL,"resolvedByUserId" TEXT,"title" TEXT NOT NULL,"description" TEXT,"severity" TEXT NOT NULL,"status" "IntegrationIncidentStatus" NOT NULL DEFAULT 'OPEN',"resolution" TEXT,"resolvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
ALTER TABLE "IntegrationMarketplaceIncident" ADD CONSTRAINT "IntegrationMarketplaceIncident_listingId_fkey" FOREIGN KEY ("listingId") REFERENCES "IntegrationMarketplaceListing"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "IntegrationMarketplaceIncident" ADD CONSTRAINT "IntegrationMarketplaceIncident_installationId_fkey" FOREIGN KEY ("installationId") REFERENCES "IntegrationInstallation"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE INDEX "IntegrationMarketplaceIncident_organizationId_status_severity_createdAt_idx" ON "IntegrationMarketplaceIncident"("organizationId","status","severity","createdAt");
